class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int[][] dp = new int[n + 1][n + 1];
        int res = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int[] arr = Arrays.copyOfRange(nums, i - 1, j);
                int hcf = findHCF(arr);
                if (hcf >= 2) {
                    dp[i][j] = j - i + 1;
                    res = Math.max(res, dp[i][j]);
                }
            }
        }
        if (res == 0) return 0;
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                if (dp[i][j] > 0) {
                    for (int k = i; k <= j; k++) {
                        if (maxC > 0 && dp[i][j] > 1) {
                            nums[k - 1] = 1;
                            maxC--;
                            res = Math.min(res, dp[i][j] - 1);
                        }
                    }
                }
            }
        }
        return res;
    }

    public int findHCF(int[] nums) {
        int hcf = nums[0];
        for (int i = 1; i < nums.length; i++) {
            hcf = gcd(hcf, nums[i]);
        }
        return hcf;
    }

    public int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
